DROP TABLE IF EXISTS `question`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `question` (
  `question_id` int NOT NULL AUTO_INCREMENT,
  `module_id` int DEFAULT NULL,
  `user_id` int DEFAULT NULL,
  `status` varchar(20) DEFAULT NULL,
  `audio_url` varchar(500) DEFAULT NULL,
  `cefr_level` varchar(5) NOT NULL,
  `content` text,
  `created_at` datetime(6) DEFAULT NULL,
  `explanation` text,
  `image_url` varchar(500) DEFAULT NULL,
  `question_type` varchar(30) NOT NULL,
  `skill` varchar(20) NOT NULL,
  `tags` varchar(500) DEFAULT NULL,
  `topic` varchar(255) DEFAULT NULL,
  `updated_at` datetime(6) DEFAULT NULL,
  `source` varchar(20) DEFAULT NULL,
  `created_method` varchar(20) DEFAULT NULL,
  `review_note` varchar(500) DEFAULT NULL,
  `reviewed_at` datetime(6) DEFAULT NULL,
  `reviewer_id` bigint DEFAULT NULL,
  `group_id` int DEFAULT NULL,
  `transcript` text,
  PRIMARY KEY (`question_id`),
  KEY `module_id` (`module_id`),
  KEY `user_id` (`user_id`),
  KEY `FKfndbgxmwikioj1tj7mxb6mmn5` (`group_id`),
  CONSTRAINT `FKfndbgxmwikioj1tj7mxb6mmn5` FOREIGN KEY (`group_id`) REFERENCES `question_group` (`group_id`),
  CONSTRAINT `question_ibfk_1` FOREIGN KEY (`module_id`) REFERENCES `module` (`module_id`),
  CONSTRAINT `question_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `user` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=123 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
