INSERT INTO `question_group` VALUES (1,NULL,'6.0',NULL,NULL,'Listen to the conversation between a student and a librarian.',NULL,'LISTENING','PUBLISHED','Education',4,NULL,NULL,NULL,NULL),(2,NULL,'7.0',NULL,NULL,'Read the article about Future Technology.',NULL,'READING','PUBLISHED','Technology',3,NULL,NULL,NULL,NULL),(3,NULL,'7.0','2026-04-18 03:24:32.625640',NULL,'Were it not for the invention of the internet, our lives would be vastly different. If scientists were to discover a cure for all diseases, it would undoubtedly have a profound impact on society. In the event that a new planet were to be discovered, it would likely be a groundbreaking finding. Unless the current rate of pollution were to slow down, the consequences would be dire. Were the government to invest more in renewable energy, it could potentially lead to a more sustainable future. In the subjunctive mood, we often express hypothetical or uncertain situations, such as \'if I were you\' or \'it is necessary that he be there.\' The use of inversions, on the other hand, can add emphasis or create a sense of formality, as seen in the phrase \'up went the balloon\' or \'never have I seen such a thing.\'',NULL,'READING','DRAFT','Quiz — Buổi 4',11,NULL,NULL,NULL,'2026-04-18 03:24:32.625640'),(4,NULL,'4.0','2026-04-18 03:29:01.962278',NULL,'My name is John. I am from England. I live in a small town. The town is very nice. It has a park, a library, and a school. I like to read books. I read books every day. Yesterday, I read a book about history. My friend, Emily, likes to watch TV. She watches TV every evening. Emily is a student. She studies at the school in our town. My mother likes to cook. She cooks dinner every night. My father likes to play football. He plays football with his friends on Sundays. I have a pet dog. His name is Max. Max is very friendly. He likes to play with me. I take Max for a walk every morning.',NULL,'READING','DRAFT','Quiz — Buổi 1',11,NULL,NULL,NULL,'2026-04-18 03:29:01.962278'