DROP TABLE IF EXISTS `quiz`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `quiz` (
  `quiz_id` int NOT NULL AUTO_INCREMENT,
  `course_id` int DEFAULT NULL,
  `user_id` int DEFAULT NULL,
  `class_id` int DEFAULT NULL,
  `quiz_category` varchar(50) DEFAULT NULL,
  `created_at` datetime(6) DEFAULT NULL,
  `description` text,
  `max_attempts` int DEFAULT NULL,
  `pass_score` decimal(5,2) DEFAULT NULL,
  `question_order` varchar(10) DEFAULT NULL,
  `show_answer_after_submit` bit(1) DEFAULT NULL,
  `status` varchar(20) DEFAULT NULL,
  `time_limit_minutes` int DEFAULT NULL,
  `title` varchar(255) DEFAULT NULL,
  `updated_at` datetime(6) DEFAULT NULL,
  `number_of_questions` int DEFAULT NULL,
  `is_open` bit(1) DEFAULT NULL,
  `lesson_id` int DEFAULT NULL,
  `module_id` int DEFAULT NULL,
  `is_hybrid_enabled` bit(1) DEFAULT NULL,
  `target_skill` varchar(20) DEFAULT NULL,
  `is_sequential` bit(1) DEFAULT NULL,
  `skill_order` json DEFAULT NULL,
  `time_limit_per_skill` json DEFAULT NULL,
  `speaking_time_limit_seconds` int DEFAULT NULL,
  `close_at` datetime(6) DEFAULT NULL,
  `deadline` datetime(6) DEFAULT NULL,
  `open_at` datetime(6) DEFAULT NULL,
  `allow_external_submission` bit(1) DEFAULT NULL,
  `external_submission_instruction` text,
  PRIMARY KEY (`quiz_id`),
  KEY `course_id` (`course_id`),
  KEY `user_id` (`user_id`),
  KEY `class_id` (`class_id`),
  KEY `FKi10d7n4lf738sm3mon21aubik` (`lesson_id`),
  KEY `FKd3pi74lbnexp6xjb3595p9088` (`module_id`),
  CONSTRAINT `FKd3pi74lbnexp6xjb3595p9088` FOREIGN KEY (`module_id`) REFERENCES `module` (`module_id`),
  CONSTRAINT `FKi10d7n4lf738sm3mon21aubik` FOREIGN KEY (`lesson_id`) REFERENCES `lesson` (`lesson_id`),
  CONSTRAINT `quiz_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `course` (`course_id`),
  CONSTRAINT `quiz_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `user` (`user_id`),
  CONSTRAINT `quiz_ibfk_3` FOREIGN KEY (`class_id`) REFERENCES `class` (`class_id`)
) ENGINE=InnoDB AUTO_INCREMENT=92 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
